// ==================== Stripe Webhook Handler ====================

async function handleStripeWebhook(request, env, corsHeaders) {
  const signature = request.headers.get('stripe-signature');

  if (!signature) {
    return jsonResponse(400, { error: 'Missing Stripe signature' }, corsHeaders);
  }

  let rawBody;
  try {
    rawBody = await request.text();
  } catch {
    return jsonResponse(400, { error: 'Failed to read request body' }, corsHeaders);
  }

  // Verify webhook signature
  const isValid = await verifyStripeWebhookSignature(rawBody, signature, env.STRIPE_WEBHOOK_SECRET);
  if (!isValid) {
    console.error('Invalid Stripe webhook signature');
    return jsonResponse(401, { error: 'Invalid webhook signature' }, corsHeaders);
  }

  let event;
  try {
    event = JSON.parse(rawBody);
  } catch {
    return jsonResponse(400, { error: 'Invalid JSON in webhook body' }, corsHeaders);
  }

  console.log(`Stripe webhook received: ${event.type}, id: ${event.id}`);

  // Process events
  try {
    switch (event.type) {
      case 'payment_intent.succeeded':
        await handlePaymentSuccess(event.data.object, env);
        break;

      case 'payment_intent.payment_failed':
        await handlePaymentFailed(event.data.object, env);
        break;

      case 'customer.subscription.created':
      case 'customer.subscription.updated':
        await handleSubscriptionUpdate(event.data.object, env);
        break;

      case 'customer.subscription.deleted':
        await handleSubscriptionCanceled(event.data.object, env);
        break;

      case 'invoice.payment_failed':
        await handleInvoicePaymentFailed(event.data.object, env);
        break;

      default:
        console.log(`Unhandled webhook event type: ${event.type}`);
    }
  } catch (err) {
    console.error(`Error processing webhook ${event.type}:`, err.message);
    // Return 200 to prevent Stripe from retrying (log the error for investigation)
    return jsonResponse(200, { received: true, processingError: true }, corsHeaders);
  }

  return jsonResponse(200, { received: true }, corsHeaders);
}

async function verifyStripeWebhookSignature(payload, sigHeader, secret) {
  if (!secret) {
    console.warn('STRIPE_WEBHOOK_SECRET not configured, skipping verification');
    return true;
  }

  try {
    const parts = sigHeader.split(',').reduce((acc, part) => {
      const [key, value] = part.split('=');
      if (key === 't') acc.timestamp = value;
      if (key === 'v1') acc.signatures = acc.signatures || [];
      if (key === 'v1') acc.signatures.push(value);
      return acc;
    }, { timestamp: null, signatures: [] });

    if (!parts.timestamp || parts.signatures.length === 0) {
      return false;
    }

    // Check timestamp tolerance (5 minutes)
    const tolerance = 300;
    const now = Math.floor(Date.now() / 1000);
    if (Math.abs(now - parseInt(parts.timestamp)) > tolerance) {
      console.error('Webhook timestamp outside tolerance');
      return false;
    }

    const signedPayload = `${parts.timestamp}.${payload}`;
    const encoder = new TextEncoder();

    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(secret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signatureBuffer = await crypto.subtle.sign('HMAC', key, encoder.encode(signedPayload));
    const expectedSignature = Array.from(new Uint8Array(signatureBuffer))
      .map(b => b.toString(16).padStart(2, '0'))
      .join('');

    return parts.signatures.some(sig => secureCompare(sig, expectedSignature));
  } catch (err) {
    console.error('Webhook signature verification failed:', err.message);
    return false;
  }
}

