// ==================== Utility Functions ====================

async function stripeRequest(method, path, params, env) {
  const url = `https://api.stripe.com${path}`;
  const options = {
    method,
    headers: {
      'Authorization': `Basic ${btoa(env.STRIPE_SECRET_KEY + ':')}`,
      'Stripe-Version': '2023-10-16',
    },
  };

  if (params && (method === 'POST' || method === 'PUT')) {
    options.headers['Content-Type'] = 'application/x-www-form-urlencoded';
    options.body = params.toString();
  }

  return fetchWithRetry(url, options);
}

function handleStripeError(data, corsHeaders) {
  const error = data.error || {};
  const statusMap = {
    'card_error': 400,
    'validation_error': 400,
    'invalid_request_error': 400,
    'authentication_error': 401,
    'rate_limit_error': 429,
    'api_error': 502,
  };

  const status = statusMap[error.type] || 500;

  return jsonResponse(status, {
    error: error.type || 'stripe_error',
    message: error.message || 'An error occurred with the payment provider',
    code: error.code || undefined,
    declineCode: error.decline_code || undefined,
  }, corsHeaders);
}

async function fetchWithRetry(url, options, maxRetries = 3) {
  let lastError;

  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      const response = await fetch(url, options);

      // Don't retry client errors
      if (response.status >= 400 && response.status < 500) {
        return response;
      }

      // Retry on 5xx or network issues
      if (response.ok || response.status < 500) {
        return response;
      }

      lastError = new Error(`HTTP ${response.status}`);
      console.warn(`Retry ${attempt + 1}/${maxRetries} for ${url}: ${response.status}`);

    } catch (err) {
      lastError = err;
      console.warn(`Retry ${attempt + 1}/${maxRetries} for ${url}: ${err.message}`);
    }

    // Exponential backoff with jitter
    if (attempt < maxRetries - 1) {
      const delay = Math.min(1000 * Math.pow(2, attempt) + Math.random() * 500, 5000);
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }

  throw lastError;
}

function mapExternalStatusCode(externalStatus) {
  if (externalStatus >= 400 && externalStatus < 500) return externalStatus;
  if (externalStatus >= 500) return 502;
  return 500;
}

function jsonResponse(status, body, corsHeaders = {}) {
  return new Response(JSON.stringify(body), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...corsHeaders,
    },
  });
}